#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=2e5+5;
int a[MAXN],n,m,l[MAXN],r[MAXN],vis[MAXN],ans; 
priority_queue<PII> st;
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cout.tie(0);
	cin>>n>>m;
	if(m>n/2)
	{
		cout<<"Error!";
		exit(false);
	}
	FOR(i,1,n)
	{
		cin>>a[i];
		st.push({a[i],i});
		l[i]=((i==1)?(n):(i-1));
		r[i]=i%n+1;
	} 
	FOR(i,1,m)
	{
		wh(vis[st.top().snd])st.pop();
		PII front=st.top();
		st.pop();
		ans+=front.fst;
		a[front.snd]=a[l[front.snd]]+a[r[front.snd]]-a[front.snd];
		st.push(mk(a[front.snd],front.snd));
		vis[l[front.snd]]=1;
		vis[r[front.snd]]=1;
		l[front.snd]=l[l[front.snd]];
		r[l[front.snd]]=front.snd;
		r[front.snd]=r[r[front.snd]];
		l[r[front.snd]]=front.snd;
	}
	cout<<ans;
    return false;
}
